-- excelfns smoke: read the READ side of the official excel extension from an
-- in-memory .xlsx BLOB handed in as a hex string (the wasm core registers
-- table-function params as VARCHAR, so the fixture is passed via from_hex).
-- Fixture: a 1-sheet workbook "Sheet1" carrying a 2x2 table:
--   A1="a" B1="b"
--   A2=1   B2=2
--
-- xlsx_sheets -> the worksheet names.
SELECT sheet FROM xlsx_sheets(from_hex(''));
-- read_xlsx -> the MELTED 2x2 table (4 cells), one (sheet, row_no, col, val) per cell.
SELECT sheet, row_no, col, val FROM read_xlsx(from_hex(''))
ORDER BY row_no, col;
-- xlsx_cell -> a single A1-addressed value (B2 = 2).
SELECT val FROM xlsx_cell(from_hex(''), 'Sheet1', 'B2');
-- Malformed blob -> zero rows (proves the function is wired, never panics).
SELECT count(*) AS bad_rows FROM read_xlsx('not an xlsx'::BLOB);
-- Empty blob -> zero rows.
SELECT count(*) AS empty_sheets FROM xlsx_sheets(''::BLOB);
